:root {
  --bg: #0b0f19;
  --accent: #38bdf8;
  --border: rgba(255, 255, 255, 0.05);
  --text: #e2e8f0;
  --text-dim: #64748b;
}

body {
  margin: 0;
  padding: 5px;
  background: transparent;
  font-family: "Inter", sans-serif;
  color: var(--text);
}

.glass-container {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  display: flex;
  flex-direction: column;
  height: 100%;
}

.table-header {
  padding: 12px 16px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 1px solid var(--border);
}

h2 {
  font-size: 1rem;
  margin: 0;
  color: var(--accent);
  font-weight: 600;
}

.search-input {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 6px 12px;
  color: white;
  font-size: 0.8rem;
  width: 180px;
}

.export-btn {
  background: transparent;
  border: 1px solid var(--accent);
  color: var(--accent);
  padding: 6px 12px;
  border-radius: 6px;
  font-size: 0.75rem;
  cursor: pointer;
  transition: 0.2s;
}

.export-btn:hover {
  background: var(--accent);
  color: #000;
}

.table-wrapper {
  flex: 1;
  overflow: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th {
  background: #111827;
  padding: 10px 16px;
  text-align: left;
  font-size: 0.7rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-dim);
  position: sticky;
  top: 0;
  z-index: 5;
}

td {
  padding: 8px 16px;
  font-size: 0.8rem;
  border-bottom: 1px solid var(--border);
}

tr:hover {
  background: rgba(255, 255, 255, 0.02);
}

/* Badges & Buttons */
.badge {
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 0.65rem;
  font-weight: 700;
}

.status-received {
  color: #10b981;
  background: rgba(16, 185, 129, 0.1);
}

.status-draft {
  color: #fbbf24;
  background: rgba(251, 191, 36, 0.1);
}

.action-group {
  display: flex;
  gap: 10px;
}

.btn-icon {
  background: transparent;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-size: 1rem;
  transition: 0.2s;
  padding: 0;
}

.btn-icon:hover {
  color: var(--accent);
  transform: scale(1.2);
}

.pagination-footer {
  padding: 8px 16px;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 15px;
  border-top: 1px solid var(--border);
}

.nav-btn {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text);
  padding: 4px 10px;
  border-radius: 4px;
  font-size: 0.75rem;
  cursor: pointer;
}

.nav-btn:disabled {
  opacity: 0.3;
}

