let currentPage = 1;
const pageSize = 25; // Set to 25 as requested
let search = "";
const formatDate = s => s ? new Date(s).toLocaleDateString('en-GB', {
  day: '2-digit',
  month: 'short'
}) : "-";
const formatAmt = n => n ? parseFloat(n).toLocaleString('en-IN', {
  minimumFractionDigits: 2
}) : "-";
document.getElementById("table-search").oninput = e => {
  search = e.target.value.toLowerCase();
  currentPage = 1;
  render();
};
document.getElementById("download-btn").onclick = () => {
  const data = getFiltered();
  const csv = ["PO Date,Number,Vendor,Amount,Status", ...data.map(r => `${r.po_date},${r.po_number},${r.vendor_name},${r.total_net},${r.status}`)].join("\n");
  const blob = new Blob([csv], {
    type: 'text/csv'
  });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'PO_Report.csv';
  a.click();
};
function getFiltered() {
  const all = appsmith.model.tableData || [];
  return all.filter(r => Object.values(r).some(v => String(v).toLowerCase().includes(search)));
}
function render() {
  const filtered = getFiltered();
  const pageData = filtered.slice((currentPage - 1) * pageSize, currentPage * pageSize);
  const totalPages = Math.ceil(filtered.length / pageSize) || 1;

  // RENDER HEADERS
  const cols = appsmith.model.columns || [];
  document.getElementById("table-head").innerHTML = `<tr>${cols.map(c => `<th>${c.label}</th>`).join("")}<th>Actions</th></tr>`;

  // RENDER BODY
  document.getElementById("table-body").innerHTML = pageData.map((item, idx) => `
        <tr>
            <td>${formatDate(item.po_date)}</td>
            <td style="font-family: monospace; color: var(--accent)">${item.po_number}</td>
            <td>${item.vendor_name}</td>
            <td style="text-align:right"><b>${formatAmt(item.total_net)}</b></td>
            <td><span class="badge status-${item.status.toLowerCase()}">${item.status}</span></td>
            <td>
                <div class="action-group">
                    <button class="btn-icon" onclick="trigger('view', ${(currentPage - 1) * pageSize + idx})">👁</button>
                    ${item.status === 'Draft' ? `<button class="btn-icon" onclick="trigger('grn', ${(currentPage - 1) * pageSize + idx})">➕</button>` : ''}
                    <button class="btn-icon" onclick="trigger('pdf', ${(currentPage - 1) * pageSize + idx})">📄</button>
                </div>
            </td>
        </tr>
    `).join("");
  document.getElementById("data-count").innerText = `${filtered.length} POs`;
  document.getElementById("page-info").innerText = `Page ${currentPage} of ${totalPages}`;
  document.getElementById("prev-btn").disabled = currentPage === 1;
  document.getElementById("next-btn").disabled = currentPage === totalPages;
}
window.trigger = (type, globalIdx) => {
  const row = getFiltered()[globalIdx];
  appsmith.updateModel({
    triggeredRow: row
  });
  appsmith.triggerEvent(type === 'view' ? "onViewClick" : type === 'grn' ? "onCreateGRNClick" : "onPDFClick");
};
document.getElementById("prev-btn").onclick = () => {
  if (currentPage > 1) {
    currentPage--;
    render();
  }
};
document.getElementById("next-btn").onclick = () => {
  if (currentPage < Math.ceil(getFiltered().length / pageSize)) {
    currentPage++;
    render();
  }
};
appsmith.onModelChange(render);

